// Logo image is embedded as base64 so it works for all roles (DSR/Admin)
// without requiring Drive access. Admin runs setupLogoCache() to populate
// LOGO_HTML_CACHE Script Property for frontend use.

'use strict';

function getEmbeddedLogoHtml() {
  return '<img src="data:image/png;base64," style="height:44px;">';
}